def connect_wifi():
    """Connect to WiFi network."""
    wlan = network.WLAN(network.STA_IF)
    wlan.active(True)
    if not wlan.isconnected():
        print("Connecting to WiFi...")
        wlan.connect(WIFI_SSID, WIFI_PASSWORD)
        timeout = 20
        while not wlan.isconnected() and timeout > 0:
            time.sleep(1)
            timeout -= 1
            print(".", end="")
    if wlan.isconnected():
        print("\nWiFi connected!")
        print("IP address:", wlan.ifconfig()[0])
        return wlan.ifconfig()[0]
    else:
        print("\nWiFi connection failed!")
        return None


def compute_websocket_accept(key):
    """Compute the Sec-WebSocket-Accept header value."""
    GUID = "258EAFA5-E914-47DA-95CA-5AB5CAFD97AB"
    combined = key.strip() + GUID
    sha1_hash = hashlib.sha1(combined.encode()).digest()
    return binascii.b2a_base64(sha1_hash).decode().strip()


def parse_http_request(data):
    """Parse HTTP upgrade request and extract WebSocket key."""
    headers = {}
    lines = data.decode("utf-8").split("\r\n")
    request_line = lines[0] if lines else ""
    for line in lines[1:]:
        if ":" in line:
            key, value = line.split(":", 1)
            headers[key.strip().lower()] = value.strip()
    return request_line, headers


def perform_handshake(client_socket):
    """Perform WebSocket handshake."""
    try:
        data = client_socket.recv(1024)
        if not data:
            return False

        request_line, headers = parse_http_request(data)

        # Check if this is a WebSocket upgrade request
        if "upgrade" not in headers.get("connection", "").lower():
            # Serve the HTML page instead
            send_html_page(client_socket)
            return False

        ws_key = headers.get("sec-websocket-key", "")
        if not ws_key:
            return False

        accept_key = compute_websocket_accept(ws_key)

        response = (
            "HTTP/1.1 101 Switching Protocols\r\n"
            "Upgrade: websocket\r\n"
            "Connection: Upgrade\r\n"
            "Sec-WebSocket-Accept: {}\r\n"
            "\r\n"
        ).format(accept_key)

        client_socket.send(response.encode())
        return True

    except Exception as e:
        print("Handshake error:", e)
        return False


def decode_websocket_frame(data):
    """Decode a WebSocket frame and return the payload."""
    if len(data) < 2:
        return None, None

    first_byte = data[0]
    second_byte = data[1]

    opcode = first_byte & 0x0F
    masked = (second_byte & 0x80) != 0
    payload_length = second_byte & 0x7F

    offset = 2

    if payload_length == 126:
        if len(data) < 4:
            return None, None
        payload_length = struct.unpack("!H", data[2:4])[0]
        offset = 4
    elif payload_length == 127:
        if len(data) < 10:
            return None, None
        payload_length = struct.unpack("!Q", data[2:10])[0]
        offset = 10

    if masked:
        if len(data) < offset + 4:
            return None, None
        mask_key = data[offset:offset + 4]
        offset += 4

    if len(data) < offset + payload_length:
        return None, None

    payload = data[offset:offset + payload_length]

    if masked:
        payload = bytes([payload[i] ^ mask_key[i % 4] for i in range(len(payload))])

    return opcode, payload


def encode_websocket_frame(data, opcode=0x01):
    """Encode data into a WebSocket frame."""
    if isinstance(data, str):
        data = data.encode("utf-8")

    frame = bytearray()
    frame.append(0x80 | opcode)  # FIN bit set + opcode

    length = len(data)
    if length < 126:
        frame.append(length)
    elif length < 65536:
        frame.append(126)
        frame.extend(struct.pack("!H", length))
    else:
        frame.append(127)
        frame.extend(struct.pack("!Q", length))

    frame.extend(data)
    return bytes(frame)


def send_to_client(client_socket, message):
    """Send a message to a single WebSocket client."""
    try:
        frame = encode_websocket_frame(message)
        client_socket.send(frame)
        return True
    except Exception as e:
        print("Send error:", e)
        return False


def broadcast(message, exclude=None):
    """Broadcast a message to all connected clients."""
    clients_lock.acquire()
    disconnected = []
    for client in clients:
        if client != exclude:
            if not send_to_client(client, message):
                disconnected.append(client)
    for client in disconnected:
        if client in clients:
            clients.remove(client)
            try:
                client.close()
            except:
                pass
    clients_lock.release()


def get_state_json():
    """Get current device state as JSON string."""
    device_state["uptime"] = time.ticks_ms() // 1000
    return json.dumps({"type": "state", "data": device_state})


def handle_command(command_data):
    """Handle incoming JSON commands and return response."""
    try:
        cmd = json.loads(command_data)
    except (ValueError, TypeError):
        return json.dumps({"type": "error", "message": "Invalid JSON"})

    action = cmd.get("action", "")
    target = cmd.get("target", "led")
    value = cmd.get("value", None)

    response = {"type": "response", "action": action, "status": "ok"}

    if action == "turn_on":
        if target == "led":
            led.value(1)
            device_state["led"] = True
            response["message"] = "LED turned ON"
        elif target == "relay":
            relay.value(1)
            device_state["relay"] = True
            response["message"] = "Relay turned ON"
        else:
            response["status"] = "error"
            response["message"] = "Unknown target: {}".format(target)

    elif action == "turn_off":
        if target == "led":
            led.value(0)
            device_state["led"] = False
            response["message"] = "LED turned OFF"
        elif target == "relay":
            relay.value(0)
            device_state["relay"] = False
            response["message"] = "Relay turned OFF"
        else:
            response["status"] = "error"
            response["message"] = "Unknown target: {}".format(target)

    elif action == "toggle":
        if target == "led":
            new_val = not device_state["led"]
            led.value(1 if new_val else 0)
            device_state["led"] = new_val
            response["message"] = "LED toggled to {}".format("ON" if new_val else "OFF")
        elif target == "relay":
            new_val = not device_state["relay"]
            relay.value(1 if new_val else 0)
            device_state["relay"] = new_val
            response["message"] = "Relay toggled to {}".format("ON" if new_val else "OFF")

    elif action == "set_brightness":
        if value is not None:
            brightness = max(0, min(100, int(value)))
            device_state["brightness"] = brightness
            # PWM control example
            try:
                pwm = machine.PWM(led, freq=1000)
                pwm.duty(int(brightness * 1023 / 100))
            except:
                pass
            response["message"] = "Brightness set to {}%".format(brightness)
        else:
            response["status"] = "error"
            response["message"] = "Value required for set_brightness"

    elif action == "get_state":
        return get_state_json()

    elif action == "ping":
        response["message"] = "pong"
        response["uptime"] = time.ticks_ms() // 1000

    elif action == "restart":
        response["message"] = "Device restarting..."
        broadcast(json.dumps(response))
        time.sleep(1)
        machine.reset()

    else:
        response["status"] = "error"
        response["message"] = "Unknown action: {}".format(action)

    return json.dumps(response)


def handle_client(client_socket, client_addr):
    """Handle a single WebSocket client connection."""
    print("New connection from:", client_addr)

    # Perform WebSocket handshake
    if not perform_handshake(client_socket):
        try:
            client_socket.close()
        except:
            pass
        return

    print("WebSocket handshake complete for:", client_addr)

    # Add to connected clients
    clients_lock.acquire()
    clients.append(client_socket)
    clients_lock.release()

    # Send initial state
    send_to_client(client_socket, get_state_json())

    # Send welcome message
    welcome = json.dumps({
        "type": "info",
        "message": "Connected to ESP32 IoT Controller",
        "clients_connected": len(clients)
    })
    send_to_client(client_socket, welcome)

    # Notify others
    broadcast(json.dumps({
        "type": "info",
        "message": "New client connected",
        "clients_connected": len(clients)
    }), exclude=client_socket)

    # Message loop
    try:
        client_socket.settimeout(0.5)
        while True:
            try:
                data = client_socket.recv(1024)
                if not data:
                    print("Client disconnected:", client_addr)
                    break

                opcode, payload = decode_websocket_frame(data)

                if opcode is None:
                    continue

                # Close frame
                if opcode == 0x08:
                    print("Close frame received from:", client_addr)
                    # Send close frame back
                    close_frame = encode_websocket_frame(b"", opcode=0x08)
                    try:
                        client_socket.send(close_frame)
                    except:
                        pass
                    break

                # Ping frame - respond with pong
                elif opcode == 0x09:
                    pong_frame = encode_websocket_frame(payload, opcode=0x0A)
                    client_socket.send(pong_frame)
                    continue

                # Pong frame - ignore
                elif opcode == 0x0A:
                    continue

                # Text frame
                elif opcode == 0x01:
                    message = payload.decode("utf-8")
                    print("Received from {}: {}".format(client_addr, message))

                    # Handle the command
                    response = handle_command(message)
                    send_to_client(client_socket, response)

                    # Broadcast state update to all clients
                    broadcast(get_state_json())

            except OSError as e:
                # Timeout - this is expected with non-blocking socket
                if e.args[0] == 110 or e.args[0] == 11:  # ETIMEDOUT or EAGAIN
                    continue
                else:
                    print("Socket error:", e)
                    break

    except Exception as e:
        print("Client handler error:", e)

    finally:
        # Remove from connected clients
        clients_lock.acquire()
        if client_socket in clients:
            clients.remove(client_socket)
        clients_lock.release()

        try:
            client_socket.close()
        except:
            pass

        print("Client disconnected:", client_addr)

        # Notify remaining clients
        broadcast(json.dumps({
            "type": "info",
            "message": "Client disconnected",
            "clients_connected": len(clients)
        }))


