def start_server(ip_address):
    """Start the WebSocket server."""
    server_socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
    server_socket.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
    server_socket.bind((ip_address, WS_PORT))
    server_socket.listen(5)

    print("=" * 50)
    print("ESP32 IoT WebSocket Server")
    print("Listening on ws://{}:{}".format(ip_address, WS_PORT))
    print("Open http://{}:{} in your browser".format(ip_address, WS_PORT))
    print("=" * 50)

    # Blink LED to indicate server is ready
    for _ in range(3):
        led.value(1)
        time.sleep(0.1)
        led.value(0)
        time.sleep(0.1)

    while True:
        try:
            client_socket, client_addr = server_socket.accept()
            # Handle each client in a new thread
            _thread.start_new_thread(handle_client, (client_socket, client_addr))
        except Exception as e:
            print("Server accept error:", e)
            time.sleep(1)


def periodic_state_broadcast():
    """Periodically broadcast device state to all clients."""
    while True:
        time.sleep(10)
        if clients:
            try:
                # Read sensor data if available (example: internal temperature)
                try:
                    import esp32
                    temp_f = esp32.raw_temperature()
                    device_state["temperature"] = round((temp_f - 32) * 5 / 9, 1)
                except:
                    pass

                broadcast(get_state_json())
            except Exception as e:
                print("Broadcast error:", e)


def main():
    """Main entry point."""
    print("Starting ESP32 IoT WebSocket Server...")

    # Initialize device state
    led.value(0)
    relay.value(0)

    # Connect to WiFi
    ip_address = connect_wifi()
    if not ip_address:
        print("Failed to connect to WiFi. Restarting in 5 seconds...")
        time.sleep(5)
        machine.reset()
        return

    # Start periodic state broadcast in background thread
    _thread.start_new_thread(periodic_state_broadcast, ())

    # Start the WebSocket server (runs forever)
    start_server(ip_address)


if __name__ == "__main__":
    main()